INSERT INTO `study_room_guide` (`study_room_id`, `contact_info`, `learning_areas`, `convenience_facilities`, `transportation_guide`)
VALUES
    (1, '电话：010-62550101\n微信：iStudySpot_WDK\n服务时间：08:00-22:30', '静音区：靠内侧独立座位，适合长时间专注学习。\n临窗区：白天采光好，适合阅读和轻度写作。\n快学区：靠近入口，适合短时复习与临时办公。', 'WiFi、饮水机、储物柜、打印复印、共享充电线、文具补给台', '地铁13号线/15号线五道口站步行6分钟，商场地下停车场可停放，工作日晚高峰建议地铁出行。'),
    (2, '电话：010-62620202\n邮箱：zgc@istudyspot.com\n服务时间：09:00-22:00', '沉浸自习区：单人桌位间距较大，适合考研备考。\n协作区：提供白板和拼桌，适合双人讨论。\n夜读区：靠近电源位，适合晚间持续学习。', '高速WiFi、白板、打印机、储物柜、咖啡机、人体工学座椅', '中关村创业大街 B2 直达，地铁4号线中关村站步行8分钟，附近共享单车停放点充足。'),
    (3, '电话：010-64770303\n微信：iStudySpot_WJ24H\n服务时间：24小时', '24小时静音舱：封闭式学习位，适合通宵复习。\n开放桌区：便于短时停留和资料整理。\n弹性休息区：夜间可短暂休息，不支持长时间占位。', '24小时门禁、自助售货机、充电接口、独立灯光、储物柜、应急毯借用', '望京 SOHO T2-3F，地铁14号线望京南站步行10分钟，夜间建议打车或步行至园区南门上车点。'),
    (4, '电话：010-82370404\n邮箱：xyl@istudyspot.com\n服务时间：07:30-23:30', '论文写作区：桌面宽、安静度高，适合电脑办公。\n标准静音区：适合日常上课与刷题。\n晨读区：靠近入口，早晨采光和流动性更好。', 'WiFi、打印复印、储物格、饮水机、雨伞借用、学习资料展示架', '学院路 37 号研学中心 2F，公交学院路北口站步行3分钟，周边停车位较紧张。'),
    (5, '电话：010-62990505\n微信：iStudySpot_XEQ\n服务时间：08:00-22:30', '标准座区：适合日常通勤学习。\n靠窗区：适合阅读和轻办公。\n讨论区：限定低声交流，适合结对学习。', 'WiFi、储物柜、打印机、饮水机、移动电源租借、无障碍通道', '西二旗数字港 B 座 4F，地铁13号线西二旗站步行9分钟，楼下有共享单车与短停落客区。'),
    (6, '电话：010-65060606\n邮箱：guomao@istudyspot.com\n服务时间：24小时', '深夜复习区：夜间照明更柔和，适合长时段复习。\n商务静音区：插座密度高，适合办公与学习兼顾。\n讨论角：可进行简短沟通，需控制音量。', '24小时门禁、WiFi、饮水机、储物柜、打印服务、安防巡检、急救包', '国贸写字楼 A 座 B1，地铁1号线/10号线国贸站地下连通，夜间可从西侧落客区进入。'),
    (7, '电话：010-84790707\n微信：iStudySpot_WJB\n服务时间：08:30-23:00', '专注区：单人位隔断明显，适合深度学习。\n轻讨论区：适合面试准备与口语练习。\n充电优先区：高频插座布局，适合携带多设备用户。', 'WiFi、充足电源、饮水机、打印机、储物柜、无障碍坡道、空气净化器', '望京北路创意园 6 号楼 1F，园区班车与公交均可到达，工作日中午停车较紧张。')
